/* Utility: find product by ID */
function getProductById(id) {
  for (var i = 0; i < PRODUCTS.length; i++) {
    if (PRODUCTS[i].id === id) return PRODUCTS[i];
  }
  return null;
}

/* Utility: get products by audience */
function getProductsByAudience(audience) {
  if (!audience || audience === 'all') return PRODUCTS;
  var result = [];
  for (var i = 0; i < PRODUCTS.length; i++) {
    if (PRODUCTS[i].audience === audience) result.push(PRODUCTS[i]);
  }
  return result;
}

/* Utility: get products by audience and category */
function getProductsByCategory(audience, catSlug) {
  var pool = getProductsByAudience(audience);
  if (!catSlug || catSlug === 'all') return pool;
  var result = [];
  for (var i = 0; i < pool.length; i++) {
    if (pool[i].catSlug === catSlug) result.push(pool[i]);
  }
  return result;
}

/* Utility: get unique categories for an audience */
function getCategoriesForAudience(audience) {
  var pool = getProductsByAudience(audience);
  var seen = {};
  var cats = [];
  for (var i = 0; i < pool.length; i++) {
    if (!seen[pool[i].catSlug]) {
      seen[pool[i].catSlug] = true;
      cats.push({ slug: pool[i].catSlug, name: pool[i].category });
    }
  }
  return cats;
}

/* Utility: get related products (same audience + category, exclude self) */
function getRelatedProducts(id, limit) {
  var product = getProductById(id);
  if (!product) return PRODUCTS.slice(0, limit || 4);
  var related = [];
  /* First pass: same audience + same category */
  for (var i = 0; i < PRODUCTS.length; i++) {
    if (PRODUCTS[i].id !== id && PRODUCTS[i].audience === product.audience && PRODUCTS[i].catSlug === product.catSlug) {
      related.push(PRODUCTS[i]);
    }
  }
  /* Second pass: same audience, different category */
  if (related.length < (limit || 4)) {
    for (var j = 0; j < PRODUCTS.length; j++) {
      if (PRODUCTS[j].id !== id && PRODUCTS[j].audience === product.audience && PRODUCTS[j].catSlug !== product.catSlug) {
        related.push(PRODUCTS[j]);
        if (related.length >= (limit || 4)) break;
      }
    }
  }
  /* Third pass: fill with anything */
  if (related.length < (limit || 4)) {
    for (var k = 0; k < PRODUCTS.length; k++) {
      if (PRODUCTS[k].id !== id && related.indexOf(PRODUCTS[k]) === -1) {
        related.push(PRODUCTS[k]);
        if (related.length >= (limit || 4)) break;
      }
    }
  }
  return related.slice(0, limit || 4);
}
